#!/bin/bash
sed -i 's/const handleLogout = () => {/const handleLogout = () => {\n    if (state.user) {\n      \/\/ Implement delayed logout\n      const startTime = Date.now();\n      const duration = 10000;\n      const overlay = document.createElement("div");\n      overlay.id = "logout-overlay";\n      overlay.style.position = "fixed";\n      overlay.style.top = "0";\n      overlay.style.left = "0";\n      overlay.style.width = "100%";\n      overlay.style.height = "100%";\n      overlay.style.backgroundColor = "rgba(15, 23, 42, 0.9)";\n      overlay.style.zIndex = "9999";\n      overlay.style.display = "flex";\n      overlay.style.flexDirection = "column";\n      overlay.style.alignItems = "center";\n      overlay.style.justifyContent = "center";\n      overlay.style.color = "white";\n      document.body.appendChild(overlay);\n\n      const title = document.createElement("h2");\n      title.style.fontSize = "1.5rem";\n      title.style.fontWeight = "bold";\n      title.style.marginBottom = "1rem";\n      title.innerText = "Saving your progress...";\n      overlay.appendChild(title);\n\n      const timer = document.createElement("div");\n      timer.style.fontSize = "3rem";\n      timer.style.fontWeight = "bold";\n      timer.style.fontFamily = "monospace";\n      overlay.appendChild(timer);\n\n      const interval = setInterval(() => {\n        const elapsed = Date.now() - startTime;\n        const remaining = Math.max(0, duration - elapsed);\n        timer.innerText = Math.ceil(remaining \/ 1000).toString();\n\n        if (remaining <= 0) {\n          clearInterval(interval);\n          saveUserToLive(state.user);\n          logActivity("LOGOUT", "User Logged Out");\n          localStorage.removeItem("nst_current_user");\n          setState(prev => ({ ...prev, user: null, originalAdmin: null, view: "BOARDS", selectedBoard: null, selectedClass: null, selectedStream: null, selectedSubject: null, lessonContent: null, language: "English" }));\n          setDailyStudySeconds(0);\n          document.body.removeChild(overlay);\n        }\n      }, 100);\n      return;\n    }/g' App.tsx
